const all = $input.all().map(i => i.json).flat().filter(x => x && typeof x === 'object' && !x.error && !x.errorMessage);
const seen = new Set();
const unique = all.filter(stock => {
  if (!stock || !stock.symbol || seen.has(stock.symbol)) return false;
  seen.add(stock.symbol);
  return true;
});
if (unique.length === 0) {
  return [{ json: { _fmp_empty: true, symbol: '_NEWS_ONLY_', price: 0 } }];
}
return unique.map(stock => ({ json: stock }));

const items = $input.all();

// FMP unavailable - pass through marker so pipeline continues with news only
if (items.length === 1 && items[0].json._fmp_empty) {
  return [{ json: { _fmp_empty: true } }];
}

const budget = $('Trigger').first().json.budget || 1000;
const market = ($('Trigger').first().json.market || 'BOTH').toUpperCase();
const fractionalShares = $('Trigger').first().json.fractional_shares !== false;

if (budget <= 0) {
  return [{ json: { error: true, response: 'Budget must be greater than 0.' } }];
}

const filtered = items.filter(item => {
  const s = item.json;
  if (!s.symbol || !s.price) return false;
  if (s.price < 1) return false;
  if (!fractionalShares && s.price > budget * 0.3) return false;
  if (s.exchange && s.exchange.includes('OTC')) return false;
  if (market === 'US' && s.symbol.includes('.')) return false;
  if (market === 'EU' && !s.symbol.includes('.')) return false;
  return true;
});

if (filtered.length === 0) {
  return [{ json: { _fmp_empty: true } }];
}

const sorted = filtered.sort((a, b) =>
  Math.abs(b.json.changesPercentage || 0) - Math.abs(a.json.changesPercentage || 0)
);

return sorted.slice(0, 10);

const first = $input.first().json;
if (first.error) {
  return [{ json: first }];
}
if (first._fmp_empty) {
  return [{ json: { _fmp_empty: true, symbols: '', symbolList: [], candidates: [] } }];
}
const symbols = $input.all().map(i => i.json.symbol).filter(Boolean);
return [{ json: { symbols: symbols.join(','), symbolList: symbols, candidates: $input.all().map(i => i.json) } }];

// Pass through markers
const firstCandidate = $('Filter Candidates').first().json;
if (firstCandidate.error) {
  return [{ json: firstCandidate }];
}
if (firstCandidate._fmp_empty) {
  return [{ json: { _fmp_empty: true } }];
}

// Resilient merge - works even if Batch Quote and Earnings Check failed
const candidates = $('Filter Candidates').all().map(i => i.json);

let earningsTickers = new Set();
try {
  const earningsRaw = $('FMP Earnings Check').all();
  if (earningsRaw && earningsRaw.length > 0) {
    const data = earningsRaw.map(e => e.json).flat();
    (Array.isArray(data) ? data : []).forEach(e => {
      if (e && e.symbol) earningsTickers.add(e.symbol);
    });
  }
} catch (e) {}

// Try to enrich with batch quote data
let quoteMap = {};
try {
  const quotes = $('FMP Batch Quote').all().map(i => i.json).flat();
  if (Array.isArray(quotes)) {
    quotes.forEach(q => { if (q && q.symbol) quoteMap[q.symbol] = q; });
  }
} catch (e) {}

return candidates.map(c => {
  const enriched = quoteMap[c.symbol] || {};
  return {
    json: {
      ...c,
      ...enriched,
      symbol: c.symbol,
      earnings_within_48h: earningsTickers.has(c.symbol),
    }
  };
});

const first = $input.first().json;
if (first.error) {
  return [{ json: first }];
}
if (first._fmp_empty) {
  // No FMP data - use general market tickers for news search
  const fallbackTickers = ['SPY','QQQ','AAPL','MSFT','TSLA'];
  return [{ json: { _fmp_empty: true, tickers: fallbackTickers.join(','), tickerList: fallbackTickers, allCandidates: [] } }];
}
const items = $input.all();
const top10 = items.slice(0, 10).map(i => i.json.symbol).filter(Boolean);
return [{ json: { tickers: top10.join(','), tickerList: top10, allCandidates: items.map(i => i.json) } }];

// Pass through hard errors only
const firstItem = $('Merge Quote Data').first().json;
if (firstItem.error) {
  return [{ json: firstItem }];
}

const fmpEmpty = firstItem._fmp_empty || false;

// Resilient news merge - works even if some sources failed
const candidates = $('Merge Quote Data').all().map(i => i.json);
const newsByTicker = {};

try {
  const fmpNews = $('FMP News').all().map(i => i.json).flat();
  const fmpArray = Array.isArray(fmpNews) ? fmpNews : [fmpNews];
  for (const n of fmpArray) {
    if (!n || !n.symbol) continue;
    if (!newsByTicker[n.symbol]) newsByTicker[n.symbol] = [];
    newsByTicker[n.symbol].push({ title: n.title || '', summary: n.text || '', source: n.site || 'FMP' });
  }
} catch (e) {}

try {
  const googleNews = $('Google News RSS').all().map(i => i.json);
  for (const n of googleNews) {
    if (!n || !n.title) continue;
    if (!newsByTicker['GENERAL']) newsByTicker['GENERAL'] = [];
    newsByTicker['GENERAL'].push({ title: n.title || '', summary: n.contentSnippet || '', source: 'Google News' });
  }
} catch (e) {}

try {
  const finnhubNews = $('Finnhub News').all().map(i => i.json).flat();
  const finnhubArray = Array.isArray(finnhubNews) ? finnhubNews : [finnhubNews];
  for (const n of finnhubArray) {
    if (!n || !n.headline) continue;
    const ticker = n.related || 'GENERAL';
    if (!newsByTicker[ticker]) newsByTicker[ticker] = [];
    newsByTicker[ticker].push({ title: n.headline || '', summary: n.summary || '', source: n.source || 'Finnhub' });
  }
} catch (e) {}

for (const ticker of Object.keys(newsByTicker)) {
  newsByTicker[ticker] = newsByTicker[ticker].slice(0, 5);
}

return [{ json: { newsByTicker, candidates: fmpEmpty ? [] : candidates, _fmp_empty: fmpEmpty } }];

// Early exit on hard errors only
const promptResult = $('Build AI Prompt').first().json;
if (promptResult.error) {
  return [{ json: promptResult }];
}

const response = $input.first().json;
const budget = promptResult.budget;
const fractionalShares = promptResult.fractionalShares;

let content = response.choices?.[0]?.message?.content || '';
content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  return [{ json: { error: true, response: 'AI returned invalid JSON. Please try scanning again.' } }];
}

if (!parsed.signals || !Array.isArray(parsed.signals)) {
  return [{ json: { error: true, response: 'AI response missing signals array.' } }];
}

const validSignals = parsed.signals.map(signal => {
  if (!signal.ticker || !signal.type) return null;

  // Default new fields
  if (!signal.trade_type) signal.trade_type = 'intraday';
  if (!signal.suggested_holding) signal.suggested_holding = signal.trade_type === 'swing' ? '2-3 days' : 'same_day';

  if (signal.type === 'BUY') {
    if ((signal.confidence || 0) < 60) {
      signal.type = 'SKIP';
      signal.reasoning = '[Auto-downgraded: confidence ' + signal.confidence + '% < 60%] ' + (signal.reasoning || '');
    }
    if ((signal.risk_reward || 0) < 1.5 && signal.type === 'BUY') {
      signal.type = 'SKIP';
      signal.reasoning = '[Auto-downgraded: R/R ' + signal.risk_reward + ' < 1.5] ' + (signal.reasoning || '');
    }
  }

  if (signal.type === 'BUY') {
    const entryMid = ((signal.entry_low || 0) + (signal.entry_high || 0)) / 2;
    if (!signal.suggested_shares && entryMid > 0) {
      const maxPosition = budget * 0.2;
      if (fractionalShares) {
        signal.suggested_shares = Math.round((maxPosition / entryMid) * 10000) / 10000;
      } else {
        signal.suggested_shares = Math.floor(maxPosition / entryMid);
      }
      signal.estimated_cost = Math.round(signal.suggested_shares * entryMid * 100) / 100;
    }
    if (!signal.upside_pct && signal.take_profit && entryMid > 0) {
      signal.upside_pct = Math.round(((signal.take_profit - entryMid) / entryMid) * 10000) / 100;
    }
    if (!signal.downside_pct && signal.stop_loss && entryMid > 0) {
      signal.downside_pct = Math.round(((signal.stop_loss - entryMid) / entryMid) * 10000) / 100;
    }
    if (!signal.risk_reward && signal.upside_pct && signal.downside_pct) {
      signal.risk_reward = Math.round(Math.abs(signal.upside_pct / signal.downside_pct) * 100) / 100;
    }
    if (!signal.potential_profit && signal.take_profit && entryMid > 0) {
      signal.potential_profit = Math.round((signal.take_profit - entryMid) * (signal.suggested_shares || 1) * 100) / 100;
    }
    if (!signal.potential_loss && signal.stop_loss && entryMid > 0) {
      signal.potential_loss = Math.round((signal.stop_loss - entryMid) * (signal.suggested_shares || 1) * 100) / 100;
    }
    if (!signal.risk_level) {
      if (signal.risk_reward > 2.5 && signal.confidence > 80) signal.risk_level = 'low';
      else if (signal.risk_reward > 1.5 && signal.confidence > 65) signal.risk_level = 'moderate';
      else signal.risk_level = 'high';
    }
    if (!signal.risk_warnings) signal.risk_warnings = [];
  }

  return { ...signal, session_date: new Date().toISOString().split('T')[0], session_budget: budget };
}).filter(Boolean);

const buySignals = validSignals.filter(s => s.type === 'BUY').slice(0, 5);
const skipSignals = validSignals.filter(s => s.type === 'SKIP');

return [{
  json: {
    signals: [...buySignals, ...skipSignals],
    market_summary: parsed.market_summary || '',
    buy_count: buySignals.length,
    skip_count: skipSignals.length,
    token_usage: response.usage || {},
  }
}];

const data = $input.first().json;

if (data.error || data._empty) {
  return [{ json: { response: data.response || 'Scanner encountered an issue. Please try again.' } }];
}

const holdingLabel = (h) => {
  if (h === 'same_day') return 'Intraday';
  return 'Swing (' + h + ')';
};

let response = `MARKET SUMMARY: ${data.market_summary}\n\n`;
response += `Found ${data.buy_count} BUY signals and ${data.skip_count} SKIP.\n\n`;

const buySignals = data.signals.filter(s => s.type === 'BUY');
const skipSignals = data.signals.filter(s => s.type === 'SKIP');

if (buySignals.length > 0) {
  response += '=== BUY SIGNALS ===\n\n';
  for (const s of buySignals) {
    response += `TICKER: ${s.ticker} (${s.company_name || s.ticker})${s.is_top_pick ? ' [TOP PICK]' : ''} | ${holdingLabel(s.suggested_holding)}\n`;
    response += `Confidence: ${s.confidence}% | Risk level: ${s.risk_level || 'N/A'}\n`;
    response += `Entry: $${s.entry_low} - $${s.entry_high}\n`;
    response += `Take-profit: $${s.take_profit} | Stop-loss: $${s.stop_loss}\n`;
    response += `Shares: ${s.suggested_shares} | Cost: $${s.estimated_cost}\n`;
    response += `Potential profit: +$${s.potential_profit} (+${s.upside_pct}%)\n`;
    response += `Potential loss: $${s.potential_loss} (${s.downside_pct}%)\n`;
    response += `Risk/Reward: ${s.risk_reward}\n`;
    if (s.risk_warnings && s.risk_warnings.length > 0) {
      response += `Warnings: ${s.risk_warnings.join(', ')}\n`;
    }
    response += `Catalysts: ${(s.catalysts || []).join(', ')}\n`;
    response += `Reasoning: ${s.reasoning}\n`;
    response += `Lesson: ${s.educational_note}\n\n`;
  }
}

if (skipSignals.length > 0) {
  response += '=== SKIP ===\n\n';
  for (const s of skipSignals.slice(0, 5)) {
    response += `${s.ticker}: ${s.reasoning}\n`;
  }
  if (skipSignals.length > 5) {
    response += `...and ${skipSignals.length - 5} more skipped.\n`;
  }
}

return [{ json: { response } }];

// Final output node - guarantees this is lastNodeExecuted
// Reads from Format Response regardless of which parallel branch finished last
return $('Format Response').all();
